	raw = TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].kosten_pro_rate" ) ) ; 1 ; 1 ) ;
	raw_clean = Substitute ( Substitute ( raw ; " " ; "" ) ; "," ; "." ) ;
	n = GetAsNumber ( raw_clean ) ;
	v = Case (
		IsEmpty ( raw ) ; "" ;
		n > 1000 ; n / 100 ;
		n
	)
];
	If ( IsEmpty ( v ) ; "" ; v )
